CREATE TABLE `candidate_results` (
	`id` int AUTO_INCREMENT NOT NULL,
	`candidatoSequencial` varchar(20) NOT NULL,
	`candidatoNome` varchar(200) NOT NULL,
	`candidatoNomeUrna` varchar(100),
	`candidatoNumero` varchar(10),
	`partidoSigla` varchar(20) NOT NULL,
	`uf` varchar(2) NOT NULL,
	`cargo` varchar(50) NOT NULL,
	`ano` smallint NOT NULL,
	`turno` tinyint NOT NULL DEFAULT 1,
	`totalVotos` bigint NOT NULL DEFAULT 0,
	`totalVotosPartido` bigint DEFAULT 0,
	`percentualSobrePartido` decimal(8,4),
	`percentualSobreValidos` decimal(8,4),
	`situacao` varchar(100),
	`eleito` boolean DEFAULT false,
	`createdAt` timestamp NOT NULL DEFAULT (now()),
	CONSTRAINT `candidate_results_id` PRIMARY KEY(`id`)
);

CREATE TABLE `candidate_zone_results` (
	`id` int AUTO_INCREMENT NOT NULL,
	`candidatoSequencial` varchar(20) NOT NULL,
	`candidatoNome` varchar(200) NOT NULL,
	`candidatoNomeUrna` varchar(100),
	`partidoSigla` varchar(20) NOT NULL,
	`uf` varchar(2) NOT NULL,
	`codigoMunicipio` varchar(10),
	`nomeMunicipio` varchar(200),
	`numeroZona` varchar(10) NOT NULL,
	`cargo` varchar(50) NOT NULL,
	`ano` smallint NOT NULL,
	`turno` tinyint NOT NULL DEFAULT 1,
	`totalVotos` bigint NOT NULL DEFAULT 0,
	`createdAt` timestamp NOT NULL DEFAULT (now()),
	CONSTRAINT `candidate_zone_results_id` PRIMARY KEY(`id`)
);

ALTER TABLE `candidates` ADD `turno` tinyint DEFAULT 1;
ALTER TABLE `candidates` ADD `eleito` boolean DEFAULT false;

CREATE INDEX `idx_cand_results_partido_uf` ON `candidate_results` (`partidoSigla`,`uf`);
CREATE INDEX `idx_cand_results_ano_cargo` ON `candidate_results` (`ano`,`cargo`);
CREATE INDEX `idx_cand_results_seq` ON `candidate_results` (`candidatoSequencial`);
CREATE INDEX `idx_cand_results_uf_ano` ON `candidate_results` (`uf`,`ano`);
CREATE INDEX `idx_zone_cand_seq` ON `candidate_zone_results` (`candidatoSequencial`);
CREATE INDEX `idx_zone_cand_uf_ano` ON `candidate_zone_results` (`uf`,`ano`);
CREATE INDEX `idx_zone_cand_partido` ON `candidate_zone_results` (`partidoSigla`);
CREATE INDEX `idx_zone_cand_municipio` ON `candidate_zone_results` (`codigoMunicipio`);
CREATE INDEX `idx_candidates_seq` ON `candidates` (`sequencial`);
ALTER TABLE `election_results_by_municipality` DROP COLUMN `candidatoNome`;
ALTER TABLE `election_results_by_municipality` DROP COLUMN `candidatoSequencial`;
ALTER TABLE `election_results_by_uf` DROP COLUMN `candidatoNome`;
ALTER TABLE `election_results_by_uf` DROP COLUMN `candidatoSequencial`;

